parameters.bodyParametersJson:
={
  "model": "llama2",
  "prompt": "You are a cybersecurity incident response expert. Analyze this security incident and provide:

Incident: {{ $json.incident_title }}
Severity: {{ $json.severity }}
Description: {{ $json.description }}
Source IP: {{ $json.source_ip }}
Target System: {{ $json.target_system }}

Provide:
1. Incident summary (2-3 sentences)
2. Threat assessment
3. Immediate actions required
4. Investigation steps
5. Containment recommendations
6. Recovery steps

Format as JSON with keys: summary, threat_level, immediate_actions (array), investigation_steps (array), containment (array), recovery (array)",
  "stream": false
}

parameters.functionCode:
// Parse AI analysis
const ollamaResponse = items[0].json.response;

let analysis;
try {
  const jsonMatch = ollamaResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  } else {
    analysis = {
      summary: ollamaResponse.substring(0, 200),
      threat_level: items[0].json.severity,
      immediate_actions: ["Investigate incident", "Contain threat"],
      investigation_steps: ["Review logs", "Analyze traffic"],
      containment: ["Block source IP", "Isolate affected system"],
      recovery: ["Restore from backup", "Verify integrity"]
    };
  }
} catch (error) {
  analysis = {
    error: error.message,
    raw_response: ollamaResponse
  };
}

return [
  {
    json: {
      incident_id: `inc_${Date.now()}`,
      title: items[0].json.incident_title,
      severity: items[0].json.severity,
      description: items[0].json.description,
      source_ip: items[0].json.source_ip,
      target_system: items[0].json.target_system,
      ai_analysis: analysis,
      detected_at: new Date().toISOString(),
      status: "investigating"
    }
  }
];

// Simulate JIRA ticket creation
const incident = items[0].json;

const ticketData = {
  ticket_id: `JIRA-${Math.floor(Math.random() * 10000)}`,
  ticket_url: `https://jira.example.com/browse/JIRA-${Math.floor(Math.random() * 10000)}`,
  project: "SECURITY",
  issue_type: "Incident",
  priority: incident.severity === "critical" ? "Highest" : "High",
  summary: incident.title,
  description: incident.description,
  labels: ["security", "incident", incident.severity],
  created_at: new Date().toISOString()
};

return [
  {
    json: {
      ...incident,
      ticket: ticketData
    }
  }
];

// Simulate notification (Email/Slack)
const incident = items[0].json;

const notification = {
  type: incident.severity === "critical" ? "email_and_slack" : "slack",
  recipients: incident.severity === "critical" 
    ? ["security-team@example.com", "ciso@example.com"]
    : ["security-team@example.com"],
  subject: `[${incident.severity.toUpperCase()}] ${incident.title}`,
  message: `Security Incident Detected\n\nSeverity: ${incident.severity}\nIncident ID: ${incident.incident_id}\nTicket: ${incident.ticket.ticket_url}\n\nSummary: ${incident.ai_analysis.summary}\n\nImmediate Actions Required:\n${incident.ai_analysis.immediate_actions.map((a, i) => `${i + 1}. ${a}`).join('\n')}`,
  sent_at: new Date().toISOString(),
  status: "sent"
};

return [
  {
    json: {
      ...incident,
      notification: notification
    }
  }
];
